18	// ExecutionResourceRootCheck captures the health of one execution root.
19	type ExecutionResourceRootCheck struct {
20		Path           string   `json:"path"`
21		Writable       bool     `json:"writable"`
22		WritableReason string   `json:"writable_reason,omitempty"`
23		BytesFree      uint64   `json:"bytes_free,omitempty"`
24		InodesFree     uint64   `json:"inodes_free,omitempty"`
25		Notes          []string `json:"notes,omitempty"`
