28	// ExecutionResourceCheckResult captures the roots and cleanup summary observed
29	// during one resource preflight.
30	type ExecutionResourceCheckResult struct {
31		ProjectRoot    string                       `json:"project_root"`
32		TempRoot       string                       `json:"temp_root"`
33		EvidenceRoots  []string                     `json:"evidence_roots,omitempty"`
34		RootChecks     []ExecutionResourceRootCheck `json:"root_checks,omitempty"`
