38	// ResourceExhaustedError signals that execution roots remained unhealthy after
39	// a cleanup retry. The caller should stop claiming new work.
40	type ResourceExhaustedError struct {
41		Detail string
42		Result ExecutionResourceCheckResult
43	}
44	
45	func (e *ResourceExhaustedError) Error() string {
46		if e == nil {
47			return "resource_exhausted"
48		}
49		if strings.TrimSpace(e.Detail) == "" {
50			return "resource_exhausted"
51		}
52		return "resource_exhausted: " + e.Detail
53	}
