59	// ExecutionResourceChecker validates DDx execution roots before claim or
60	// worktree creation. It is safe for tests to override RootProbe and
61	// CleanupRunner to simulate low-space or cleanup-recovery scenarios.
62	type ExecutionResourceChecker interface {
63		Check(ctx context.Context) (ExecutionResourceCheckResult, error)
64	}
