66	// ExecutionResourcePreflight is the default checker used by ddx try/work.
67	type ExecutionResourcePreflight struct {
68		ProjectRoot   string
69		TempRoot      string
70		EvidenceRoots []string
71		GitOps        GitOps
72	
73		CleanupRunner executionCleanupRunner
74		RootProbe     func(path string) (ExecutionResourceRootCheck, error)
75	}
