77	// NewExecutionResourceChecker constructs the default preflight checker.
78	func NewExecutionResourceChecker(projectRoot string, gitOps GitOps) *ExecutionResourcePreflight {
79		return &ExecutionResourcePreflight{
80			ProjectRoot: projectRoot,
81			TempRoot:    executionCleanupTempRoot(projectRoot),
82			EvidenceRoots: []string{
83				filepath.Join(projectRoot, ExecuteBeadArtifactDir),
84				filepath.Join(projectRoot, ".ddx", "runs"),
85			},
86			GitOps:        gitOps,
87			CleanupRunner: NewExecutionCleanupManager(projectRoot, gitOps),
88			RootProbe:     probeExecutionRoot,
89		}
90	}
