92	func (p *ExecutionResourcePreflight) Check(ctx context.Context) (ExecutionResourceCheckResult, error) {
93		if ctx == nil {
94			ctx = context.Background()
95		}
96		if p == nil {
97			return ExecutionResourceCheckResult{}, nil
98		}
99	
100		result := ExecutionResourceCheckResult{
101			ProjectRoot:   p.projectRoot(),
102			TempRoot:      p.tempRoot(),
103			EvidenceRoots: p.evidenceRoots(),
104		}
105	
106		checks, detail, healthy := p.checkRoots()
107		result.RootChecks = checks
108		if healthy {
109			return result, nil
110		}
111	
112		if p.CleanupRunner != nil {
113			summary, cleanupErr := p.CleanupRunner.Cleanup(ctx)
114			result.CleanupSummary = summary
115			if cleanupErr != nil {
116				if detail != "" {
117					detail += "; "
118				}
119				detail += "cleanup: " + cleanupErr.Error()
120			}
121		}
122	
123		checks, recheckDetail, recheckHealthy := p.checkRoots()
124		result.RootChecks = checks
125		if recheckHealthy {
126			return result, nil
127		}
128		if recheckDetail != "" {
129			detail = recheckDetail
130		}
131		return result, &ResourceExhaustedError{Detail: detail, Result: result}
132	}
