164	func (p *ExecutionResourcePreflight) checkRoots() ([]ExecutionResourceRootCheck, string, bool) {
165		roots := p.allRoots()
166		checks := make([]ExecutionResourceRootCheck, 0, len(roots))
167		var details []string
168		healthy := true
169		for _, root := range roots {
170			check, err := p.checkRoot(root)
171			checks = append(checks, check)
172			if err != nil {
173				healthy = false
174				details = append(details, err.Error())
175			}
176		}
177		return checks, strings.Join(details, "; "), healthy
178	}
