180	func (p *ExecutionResourcePreflight) checkRoot(root string) (ExecutionResourceRootCheck, error) {
181		check := ExecutionResourceRootCheck{Path: root}
182		if strings.TrimSpace(root) == "" {
183			check.Notes = append(check.Notes, "empty root")
184			return check, fmt.Errorf("resource preflight: empty root")
185		}
186		if err := os.MkdirAll(root, 0o755); err != nil {
187			check.Notes = append(check.Notes, "mkdir: "+err.Error())
188			return check, fmt.Errorf("resource preflight: %s: mkdir: %w", root, err)
189		}
190	
191		writable, writableReason := probeWritableRoot(root)
192		check.Writable = writable
193		check.WritableReason = writableReason
194		if !writable {
195			check.Notes = append(check.Notes, writableReason)
196			return check, fmt.Errorf("resource preflight: %s: %s", root, writableReason)
197		}
198	
199		if p.RootProbe != nil {
200			probed, err := p.RootProbe(root)
201			if err != nil {
202				check.Notes = append(check.Notes, err.Error())
203				return check, err
204			}
205			check.BytesFree = probed.BytesFree
206			check.InodesFree = probed.InodesFree
207			check.Notes = append(check.Notes, probed.Notes...)
208			if !probed.Writable {
209				msg := probed.WritableReason
210				if msg == "" {
211					msg = "root probe reported unwritable"
212				}
213				check.Notes = append(check.Notes, msg)
214				return check, fmt.Errorf("resource preflight: %s: %s", root, msg)
215			}
216			if probed.BytesFree > 0 && probed.BytesFree < executionResourceMinFreeBytes {
217				msg := fmt.Sprintf("free bytes %d < required %d", probed.BytesFree, executionResourceMinFreeBytes)
218				check.Notes = append(check.Notes, msg)
219				return check, fmt.Errorf("resource preflight: %s: %s", root, msg)
220			}
221			if probed.InodesFree > 0 && probed.InodesFree < executionResourceMinFreeInodes {
222				msg := fmt.Sprintf("free inodes %d < required %d", probed.InodesFree, executionResourceMinFreeInodes)
223				check.Notes = append(check.Notes, msg)
224				return check, fmt.Errorf("resource preflight: %s: %s", root, msg)
225			}
226			return check, nil
227		}
228	
229		bytesFree, inodesFree, err := probeRootCapacity(root)
230		if err != nil {
231			check.Notes = append(check.Notes, err.Error())
232			return check, err
233		}
234		check.BytesFree = bytesFree
235		check.InodesFree = inodesFree
236		if bytesFree > 0 && bytesFree < executionResourceMinFreeBytes {
237			msg := fmt.Sprintf("free bytes %d < required %d", bytesFree, executionResourceMinFreeBytes)
238			check.Notes = append(check.Notes, msg)
239			return check, fmt.Errorf("resource preflight: %s: %s", root, msg)
240		}
241		if inodesFree > 0 && inodesFree < executionResourceMinFreeInodes {
242			msg := fmt.Sprintf("free inodes %d < required %d", inodesFree, executionResourceMinFreeInodes)
243			check.Notes = append(check.Notes, msg)
244			return check, fmt.Errorf("resource preflight: %s: %s", root, msg)
245		}
246		return check, nil
247	}
