249	func probeWritableRoot(root string) (bool, string) {
250		f, err := os.CreateTemp(root, ".ddx-resource-preflight-*")
251		if err != nil {
252			return false, "writability check failed: " + err.Error()
253		}
254		name := f.Name()
255		if closeErr := f.Close(); closeErr != nil {
256			_ = os.Remove(name)
257			return false, "writability check close failed: " + closeErr.Error()
258		}
259		if removeErr := os.Remove(name); removeErr != nil {
260			return false, "writability check remove failed: " + removeErr.Error()
261		}
262		return true, ""
263	}
