265	func probeExecutionRoot(root string) (ExecutionResourceRootCheck, error) {
266		check := ExecutionResourceRootCheck{Path: root}
267		writable, writableReason := probeWritableRoot(root)
268		check.Writable = writable
269		check.WritableReason = writableReason
270		if !writable {
271			return check, fmt.Errorf("resource preflight: %s: %s", root, writableReason)
272		}
273		bytesFree, inodesFree, err := probeRootCapacity(root)
274		if err != nil {
275			return check, fmt.Errorf("resource preflight: %s: %w", root, err)
276		}
277		check.BytesFree = bytesFree
278		check.InodesFree = inodesFree
279		return check, nil
280	}
