282	func probeRootCapacity(root string) (bytesFree uint64, inodesFree uint64, err error) {
283		var stat unix.Statfs_t
284		if err := unix.Statfs(root, &stat); err != nil {
285			return 0, 0, fmt.Errorf("statfs %s: %w", root, err)
286		}
287		bytesFree = uint64(stat.Bavail) * uint64(stat.Bsize)
288		inodesFree = uint64(stat.Ffree)
289		return bytesFree, inodesFree, nil
290	}
